package com.exam.dto;

import lombok.Data;

import java.math.BigDecimal;
import java.time.LocalDateTime;

/**
 * 成绩分析响应
 */
@Data
public class ScoreAnalysisResponse {

    private Long userId;
    private String displayName;
    private BigDecimal score;
    private LocalDateTime startTime;
    private LocalDateTime endTime;
    private Integer attemptNo;
}

package com.exam.dto;

import lombok.Data;

/**
 * 题目分析响应
 */
@Data
public class QuestionAnalysisResponse {

    private Long questionId;
    private String content;
    private Integer totalAnswered;
    private Integer correctCount;
    /** 正确率（0-100），在 Service 层计算 */
    private Double correctRate;
}

package com.exam.mapper;

import com.baomidou.mybatisplus.core.metadata.IPage;
import com.exam.dto.QuestionAnalysisResponse;
import com.exam.dto.ScoreAnalysisResponse;
import org.apache.ibatis.annotations.Mapper;
import org.apache.ibatis.annotations.Param;

import java.util.List;

/**
 * 试卷分析 Mapper
 */
@Mapper
public interface AnalysisMapper {

    IPage<ScoreAnalysisResponse> selectScoreAnalysis(IPage<?> page, @Param("examId") Long examId);

    List<QuestionAnalysisResponse> selectQuestionAnalysis(@Param("examId") Long examId);
}

package com.exam.service;

import com.baomidou.mybatisplus.core.metadata.IPage;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import com.exam.dto.QuestionAnalysisResponse;
import com.exam.dto.ScoreAnalysisResponse;
import com.exam.mapper.AnalysisMapper;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.List;

/**
 * 试卷分析服务
 */
@Service
public class AnalysisService {

    private final AnalysisMapper analysisMapper;

    public AnalysisService(AnalysisMapper analysisMapper) {
        this.analysisMapper = analysisMapper;
    }

    /**
     * 成绩分析（分页）
     */
    public IPage<ScoreAnalysisResponse> scoreAnalysis(Long examId, int page, int size) {
        return analysisMapper.selectScoreAnalysis(new Page<>(page, size), examId);
    }

    /**
     * 题目分析：查询后在内存中计算正确率
     */
    public List<QuestionAnalysisResponse> questionAnalysis(Long examId) {
        List<QuestionAnalysisResponse> list = analysisMapper.selectQuestionAnalysis(examId);
        for (QuestionAnalysisResponse item : list) {
            if (item.getTotalAnswered() != null && item.getTotalAnswered() > 0) {
                // 正确率 = correctCount * 100.0 / totalAnswered，保留1位小数
                double rate = BigDecimal.valueOf(item.getCorrectCount() * 100.0)
                        .divide(BigDecimal.valueOf(item.getTotalAnswered()), 1, RoundingMode.HALF_UP)
                        .doubleValue();
                item.setCorrectRate(rate);
            } else {
                item.setCorrectRate(0.0);
            }
        }
        return list;
    }
}

package com.exam.controller.admin;

import com.baomidou.mybatisplus.core.metadata.IPage;
import com.exam.dto.QuestionAnalysisResponse;
import com.exam.dto.Result;
import com.exam.dto.ScoreAnalysisResponse;
import com.exam.service.AnalysisService;
import org.springframework.web.bind.annotation.*;

import java.util.List;

/**
 * 管理员 - 试卷分析接口
 */
@RestController
@RequestMapping("/api/admin/exams/{examId}/analysis")
public class AdminAnalysisController {

    private final AnalysisService analysisService;

    public AdminAnalysisController(AnalysisService analysisService) {
        this.analysisService = analysisService;
    }

    @GetMapping("/scores")
    public Result<IPage<ScoreAnalysisResponse>> scores(
            @PathVariable Long examId,
            @RequestParam(defaultValue = "1") int page,
            @RequestParam(defaultValue = "10") int size) {
        return Result.ok(analysisService.scoreAnalysis(examId, page, size));
    }

    @GetMapping("/questions")
    public Result<List<QuestionAnalysisResponse>> questions(@PathVariable Long examId) {
        return Result.ok(analysisService.questionAnalysis(examId));
    }
}
